message.content:
@startuml
skinparam backgroundColor #FFFFFF
skinparam sequenceMessageAlign center

participant "PicYaPaletteActivity" as PPA {
}
participant "ImageChooserActivity" as ICA {
}
participant "SettingsActivity" as SA {
}

PPA ->> PPA : onCreate
activate PPA
PPA ->> ICA : startActivity
activate ICA
ICA ->> ICA : openSettings
activate ICA
ICA ->> SA : startActivity
activate SA
SA ->> SA : savePreferences
deactivate SA
SA --> ICA 
deactivate ICA
ICA --> PPA 
deactivate PPA
@enduml
